const fs = require('fs');
const path = require('path');

const root = path.resolve(__dirname, '..');
const contentDir = path.join(root, 'content');
const outputFile = path.join(contentDir, 'content-bundle.js');
const canonicalContentRoot = fs.realpathSync.native
  ? fs.realpathSync.native(contentDir)
  : fs.realpathSync(contentDir);

function assertContainedRealPath(targetPath, canonicalRoot, fsApi = fs) {
  const stats = fsApi.lstatSync(targetPath);
  if (stats.isSymbolicLink()) {
    throw new Error(`Refusing symbolic link or reparse point in content: ${targetPath}`);
  }

  const realPath = fsApi.realpathSync.native
    ? fsApi.realpathSync.native(targetPath)
    : fsApi.realpathSync(targetPath);
  const relative = path.relative(canonicalRoot, realPath);
  const contained = relative === ''
    || (!path.isAbsolute(relative) && relative !== '..' && !relative.startsWith(`..${path.sep}`));
  if (!contained) {
    throw new Error(`Content path escapes canonical content root: ${targetPath} -> ${realPath}`);
  }

  return stats;
}

function walk(targetPath, canonicalRoot = canonicalContentRoot, fsApi = fs) {
  const stats = assertContainedRealPath(targetPath, canonicalRoot, fsApi);
  if (!stats.isDirectory()) return [targetPath];

  return fsApi.readdirSync(targetPath)
    .sort((left, right) => left.localeCompare(right))
    .flatMap((name) => walk(path.join(targetPath, name), canonicalRoot, fsApi));
}

function rel(file) {
  return path.relative(root, file).replace(/\\/g, '/');
}

function assertSafeRelativePath(relativePath) {
  if (typeof relativePath !== 'string') {
    throw new Error(`Unsafe bundled content path: ${relativePath}`);
  }

  const normalized = relativePath.replace(/\\/g, '/');
  const resolved = path.resolve(root, normalized);
  const withinRoot = resolved.startsWith(`${root}${path.sep}`);
  const normalizedPath = path.posix.normalize(normalized);
  const unsafeSegment = normalized.split('/').some((segment) => !segment || segment === '.' || segment === '..');

  if (
    path.isAbsolute(relativePath)
    || !withinRoot
    || normalized !== normalizedPath
    || unsafeSegment
    || !normalized.startsWith('content/')
    || /#U[0-9a-f]{4}/i.test(normalized)
  ) {
    throw new Error(`Unsafe bundled content path: ${relativePath}`);
  }

  return normalized;
}

function buildContentBundle() {
  const markdown = {};
  const json = {};

  for (const file of walk(contentDir)) {
    const relative = assertSafeRelativePath(rel(file));
    if (relative === 'content/content-bundle.js') continue;
    if (file.toLowerCase().endsWith('.md')) {
      markdown[relative] = fs.readFileSync(file, 'utf8');
    }
    if (file.toLowerCase().endsWith('.json')) {
      try {
        json[relative] = JSON.parse(fs.readFileSync(file, 'utf8'));
      } catch (error) {
        console.warn(`Skipped invalid JSON: ${relative}`);
      }
    }
  }

  const output = `// Aleksi Lab static content bundle. Enables article/math pages to work when opened from file://.\n` +
    `// Generated by scripts/build-content-bundle.js. Run \`npm run build\` after adding Markdown notes.\n` +
    `window.ALEKSI_MARKDOWN_BUNDLE = ${JSON.stringify(markdown)};\n` +
    `window.ALEKSI_JSON_BUNDLE = ${JSON.stringify(json)};\n`;

  fs.writeFileSync(outputFile, output, 'utf8');
  console.log(`Built content/content-bundle.js with ${Object.keys(markdown).length} Markdown files and ${Object.keys(json).length} JSON files.`);
}

if (require.main === module) buildContentBundle();

module.exports = {
  assertContainedRealPath,
  buildContentBundle,
  walk
};
